        /// </summary>
        /// <param name="oBPv310CreateMethodRoutingRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv310CreateMethodRoutingApiResponse"/>&gt;</returns>
        public async Task<IOBPv310CreateMethodRoutingApiResponse?> OBPv310CreateMethodRoutingOrDefaultAsync(OBPv310CreateMethodRoutingRequest oBPv310CreateMethodRoutingRequest, System.Threading.CancellationToken cancellationToken = default)
        {
